'/%3E%3C/g%3E%3C/g%3E%3C/svg%3E");pointer-events:none}\n.ps-comp-ace-label{font-family:\'JetBrains Mono\',monospace;font-size:12px;font-weight:600;color:#92400e;letter-spacing:3px;text-transform:uppercase;margin-bottom:20px;position:relative;z-index:1}\n.ps-comp-ace-quote{font-size:20px;color:rgba(255,255,255,0.95);line-height:1.6;max-width:800px;margin:0 auto;position:relative;z-index:1}\n.ps-comp-ace-quote strong{color:#0369a1}\n@media(max-width:1024px){\n  .ps-comp-grid{grid-template-columns:1fr}\n}\n@media(max-width:768px){\n  .ps-comp-section{padding:80px 20px}\n  .ps-comp-title{font-size:32px}\n  .ps-comp-ace{padding:32px 24px}\n  .ps-comp-ace-quote{font-size:16px}\n}\n/* Divi line-height overrides */\n.et_pb_section .ps-comp-label{line-height:19.2px !important}\n.et_pb_section .ps-comp-tag{line-height:17.6px !important}\n.et_pb_section .ps-comp-use-when{line-height:19.2px !important}\n.et_pb_section .ps-comp-use-when strong{line-height:19.2px !important}\n.et_pb_section .ps-comp-ace-label{line-height:19.2px !important}\n@media(prefers-reduced-motion:reduce){.ps-comp-card{transition:none !important}}\n/* === CTA: SEE THE ECONOMICS === */\n.ps-cta-section{background:linear-gradient(135deg, #00AFF0 0%, #003CC8 100%);padding:100px 24px;position:relative;overflow:hidden;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px}\n.ps-cta-section::before{content:\'\';position:absolute;top:0;left:0;right:0;bottom:0;background-image:url("data:image/svg+xml,%3Csvg width=\'20\' height=\'20\' viewBox=\'0 0 20 20\' xmlns=\'http://www.w3.org/2000/svg\'%3E%3Cpath d=\'M10 0v20M0 10h20\' stroke=\'%23fff\' stroke-width=\'0.5\' opacity=\'0.05\'/%3E%3C/svg%3E");pointer-events:none;z-index:1}\n.ps-cta-section::after{content:\'\';position:absolute;bottom:-20%;right:-10%;width:80%;height:80%;background:radial-gradient(ellipse at center,rgba(255,255,255,0.1) 0%,transparent 70%);pointer-events:none;z-index:1}\n.ps-cta-super-d{position:absolute;top:50%;right:auto;left:-15%;width:60%;min-height:60vh;background:url("data:image/svg+xml;base64,") no-repeat center left;background-size:contain;transform:translateY(-50%);opacity:0.14;pointer-events:none;z-index:0}\n.ps-cta-wave-flow{position:absolute;bottom:0;left:0;right:0;height:160px;background:linear-gradient(180deg,transparent,rgba(0,60,200,0.15));opacity:0.3;z-index:1;pointer-events:none}\n.ps-cta-container{position:relative;z-index:3;max-width:800px;margin:0 auto;text-align:center}\n.ps-cta-title{font-family:\'Noto Sans\',sans-serif;font-weight:700;font-size:40px;color:#fff;line-height:1.6;margin:0 0 16px}\n.ps-cta-subtitle{font-family:\'Noto Sans\',sans-serif;font-size:18px;color:rgba(255,255,255,0.9);margin:0 0 40px;max-width:600px;margin-left:auto;margin-right:auto}\n/* Divi overrides — ensure font properties survive Divi cascade */\n.et_pb_section .ps-cta-title{font-weight:700 !important;font-size:40px !important;line-height:1.6 !important;color:#fff !important}\n.et_pb_section .ps-cta-subtitle{font-weight:400 !important;padding-bottom:0 !important}\n.et_pb_section .ps-cta-container p{padding-bottom:0 !important}\n\n.ps-cta-btn{font-family:\'Noto Sans\',sans-serif;font-size:16px;font-weight:600;padding:16px 32px;border-radius:8px;cursor:pointer;transition:all 0.3s ease;text-decoration:none;display:inline-flex;align-items:center;gap:8px;position:relative;overflow:hidden;border:none;line-height:1.6}\n.ps-cta-btn::before{content:\'\';position:absolute;top:0;left:-100%;width:100%;height:100%;background:linear-gradient(90deg,transparent,rgba(255,255,255,0.2),transparent);transition:left 0.5s}\n.ps-cta-btn:hover::before{left:100%}\n.ps-cta-btn--primary{background:#fff;color:#003CC8;font-weight:600;box-shadow:0 4px 20px rgba(0,0,0,0.15)}\n.ps-cta-btn--primary:hover{transform:translateY(-3px);box-shadow:0 12px 40px rgba(0,0,0,0.2)}\n.ps-cta-btn--ghost{background:transparent;color:#fff;border:2px solid rgba(255,255,255,0.6)}\n.ps-cta-btn--ghost:hover{background:rgba(255,255,255,0.15);border-color:#fff}\n.ps-cta-btn-row{display:flex;gap:20px;flex-wrap:wrap;justify-content:center;position:relative;z-index:2}\n.ps-cta-btn{position:static;overflow:visible;display:inline-flex;align-items:center;gap:8px;padding:16px 32px;border-radius:8px;line-height:1.6}\n@media(max-width:767px){\n  .ps-cta-title{font-size:28px;margin-bottom:16px}\n  .ps-cta-subtitle{font-size:16px;margin-bottom:32px}\n  .ps-cta-btn-row{flex-direction:column;align-items:stretch;gap:16px}\n  .ps-cta-btn{width:100%;max-width:300px;margin:0 auto;text-align:center}\n}\n@media(prefers-reduced-motion:reduce){.ps-cta-btn{transition:none !important}.ps-cta-btn::before{display:none}}\n\n/* === TB BODY WRAPPER RESET (must be last — beats :has() rules and Divi mobile padding) === */\n/* .et-l--body doesn\'t exist on all WP/Divi versions — use [class*="tb_body"] directly */\n.et_pb_section[class*="tb_body"].et_section_regular{background:transparent !important;background-image:none !important;padding:0 !important;margin:0 !important}\n.et_pb_row[class*="tb_body"].et_pb_row{max-width:100% !important;width:100% !important;padding:0 !important;margin:0 !important}\n.et_pb_column[class*="tb_body"]{padding:0 !important;margin:0 !important}\n@media(max-width:640px){\n  .et_pb_section .et_pb_row[class*="tb_body"].et_pb_row{padding:0 !important}\n}</style><!-- /wp:html -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Hero: Solution Stack"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Hero: Solution Stack: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Hero: Solution Stack: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="ps-hero-section">\n      <div class="ps-hero-d-bg" aria-hidden="true"></div>\n      <div class="ps-hero-dot-overlay" aria-hidden="true"></div>\n      <div class="ps-hero-grain" aria-hidden="true"></div>\n      <div class="ps-hero-inner">\n        <div class="ps-hero-breadcrumb">\n          <a href="/partner-program/">Partner Program</a>\n          <span>/</span>\n          <span>Solution Stack</span>\n        </div>\n        <h1 class="ps-hero-title">Stop Building Custom Code.<br><span class="ps-hero-hl">Start Deploying a Modular Arsenal.</span></h1>\n        <p class="ps-hero-subtitle">You’re not just reselling software. You’re deploying a complete Customer Lifecycle Management strategy—land with one product, expand to the full stack, lock in recurring revenue for years.</p>\n        <div class="ps-hero-stats">\n          <div class="ps-hero-stat">\n            <div class="ps-hero-stat-value dw-years">44</div>\n            <div class="ps-hero-stat-label">Years of R&D Investment</div>\n          </div>\n          <div class="ps-hero-stat">\n            <div class="ps-hero-stat-value">50K+</div>\n            <div class="ps-hero-stat-label">Manufacturing Clients</div>\n          </div>\n          <div class="ps-hero-stat">\n            <div class="ps-hero-stat-value">4</div>\n            <div class="ps-hero-stat-label">Revenue Engines</div>\n          </div>\n        </div>\n      </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Products: Solution Stack"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Products: Solution Stack: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Products: Solution Stack: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="ps-prod-section">\n      <div class="ps-prod-scene"><svg viewBox="0 0 1400 900" fill="none" xmlns="http://www.w3.org/2000/svg" preserveAspectRatio="xMidYMid slice" aria-hidden="true">\n  <circle cx="700" cy="450" r="60" stroke="#000864" stroke-width="2" fill="none" opacity="0.15"/>\n  <circle cx="700" cy="450" r="30" stroke="#00AFF0" stroke-width="1.5" fill="none" opacity="0.12"/>\n  <circle cx="700" cy="450" r="6" fill="#000864" opacity="0.2"/>\n  <rect x="200" y="150" width="100" height="70" rx="8" stroke="#000864" stroke-width="2" fill="none" opacity="0.15"/>\n  <line x1="300" y1="185" x2="645" y2="420" stroke="#000864" stroke-width="1.5" opacity="0.1"/>\n  <rect x="1100" y="150" width="100" height="70" rx="8" stroke="#000864" stroke-width="2" fill="none" opacity="0.15"/>\n  <line x1="1100" y1="185" x2="755" y2="420" stroke="#000864" stroke-width="1.5" opacity="0.1"/>\n  <rect x="200" y="650" width="100" height="70" rx="8" stroke="#000864" stroke-width="2" fill="none" opacity="0.15"/>\n  <line x1="300" y1="685" x2="645" y2="480" stroke="#000864" stroke-width="1.5" opacity="0.1"/>\n  <rect x="1100" y="650" width="100" height="70" rx="8" stroke="#000864" stroke-width="2" fill="none" opacity="0.15"/>\n  <line x1="1100" y1="685" x2="755" y2="480" stroke="#000864" stroke-width="1.5" opacity="0.1"/>\n  <path d="M470 300 L480 310 L500 290" stroke="#00AFF0" stroke-width="2" fill="none" opacity="0.2"/>\n  <path d="M900 300 L910 310 L930 290" stroke="#00AFF0" stroke-width="2" fill="none" opacity="0.2"/>\n  <path d="M470 580 L480 590 L500 570" stroke="#00AFF0" stroke-width="2" fill="none" opacity="0.18"/>\n  <path d="M900 580 L910 590 L930 570" stroke="#00AFF0" stroke-width="2" fill="none" opacity="0.18"/>\n  <circle cx="400" cy="340" r="4" fill="#000864" opacity="0.12"/>\n  <circle cx="1000" cy="340" r="4" fill="#000864" opacity="0.12"/>\n</svg></div>\n      <div class="ps-prod-wave-left" aria-hidden="true"></div>\n      <div class="ps-prod-inner">\n        <div class="ps-prod-header">\n          <h2 class="ps-prod-title">Your Product Portfolio as Revenue Engines</h2>\n          <p class="ps-prod-subtitle">Each product isn’t just software—it’s a business model with specific revenue characteristics and cross-sell paths.</p>\n        </div>\n        \n            <div class="ps-prod-card">\n              <div class="ps-prod-info">\n                <span class="ps-prod-badge">The “Enterprise Alternative”</span>\n                <h3>T100 Enterprise ERP</h3>\n                <p class="ps-prod-desc">Win the “Big Fish” accounts—multi-site automotive and electronics suppliers—that usually go to enterprise ERP vendors. Offer <strong>Tier-1 capability at Tier-2 pricing</strong>, targeting EV supply chain factories that need bilingual support and complex costing.</p>\n                <ul class="ps-prod-features"><li><svg viewBox="0 0 24 24" fill="none" stroke-width="2" aria-hidden="true"><polyline points="20 6 9 17 4 12"/></svg><span>Multi-site, multi-currency, multi-company architecture</span></li><li><svg viewBox="0 0 24 24" fill="none" stroke-width="2" aria-hidden="true"><polyline points="20 6 9 17 4 12"/></svg><span>Complex costing logic for automotive & electronics</span></li><li><svg viewBox="0 0 24 24" fill="none" stroke-width="2" aria-hidden="true"><polyline points="20 6 9 17 4 12"/></svg><span>Chinese/Thai/English bilingual out of the box</span></li><li><svg viewBox="0 0 24 24" fill="none" stroke-width="2" aria-hidden="true"><polyline points="20 6 9 17 4 12"/></svg><span><strong>Cross-sell path:</strong> T100 → MES → WMS → AIoT → BPM</span></li></ul>\n                <a href="/products/erp/" class="ps-prod-link">Learn more about T100 <svg viewBox="0 0 24 24" fill="none" stroke-width="2" aria-hidden="true"><line x1="5" y1="12" x2="19" y2="12"/><polyline points="12 5 19 12 12 19"/></svg></a>\n              </div>\n              <div class="ps-prod-metrics">\n                <div class="ps-prod-metrics-title">Your Revenue Model: High-Value Project</div>\n                <div class="ps-prod-metric">\n        <span class="ps-prod-metric-label">Target Customer</span>\n        <span class="ps-prod-metric-value">200+ employees</span>\n      </div><div class="ps-prod-metric">\n        <span class="ps-prod-metric-label">License Margin</span>\n        <span class="ps-prod-metric-value ps-prod-metric-hl">30-40%</span>\n      </div><div class="ps-prod-metric">\n        <span class="ps-prod-metric-label">Implementation Fees</span>\n        <span class="ps-prod-metric-value ps-prod-metric-hl">100% yours</span>\n      </div><div class="ps-prod-metric">\n        <span class="ps-prod-metric-label">Revenue Type</span>\n        <span class="ps-prod-metric-value">Enterprise Asset</span>\n      </div>\n              </div>\n            </div>\n            <div class="ps-prod-card">\n              <div class="ps-prod-info">\n                <span class="ps-prod-badge">The “Volume Engine”</span>\n                <h3>Workflow iGP Growth ERP</h3>\n                <p class="ps-prod-desc">Your “Rapid Deployment” weapon for Thai SMEs. Addresses the massive automation gap where local accounting fails to handle production logic, but global ERPs are too expensive. <strong>Pre-localized for Thai Revenue Department (certified).</strong></p>\n                <ul class="ps-prod-features"><li><svg viewBox="0 0 24 24" fill="none" stroke-width="2" aria-hidden="true"><polyline points="20 6 9 17 4 12"/></svg><span>3-6 month deployments—turn projects faster, bill sooner</span></li><li><svg viewBox="0 0 24 24" fill="none" stroke-width="2" aria-hidden="true"><polyline points="20 6 9 17 4 12"/></svg><span>Lower barrier = higher volume of local manufacturers</span></li><li><svg viewBox="0 0 24 24" fill="none" stroke-width="2" aria-hidden="true"><polyline points="20 6 9 17 4 12"/></svg><span>Thai taxation certified—easy sell to Finance Directors</span></li><li><svg viewBox="0 0 24 24" fill="none" stroke-width="2" aria-hidden="true"><polyline points="20 6 9 17 4 12"/></svg><span><strong>Cross-sell path:</strong> iGP → MES → WMS → AIoT</span></li></ul>\n                <a href="/products/erp/" class="ps-prod-link">Learn more about iGP <svg viewBox="0 0 24 24" fill="none" stroke-width="2" aria-hidden="true"><line x1="5" y1="12" x2="19" y2="12"/><polyline points="12 5 19 12 12 19"/></svg></a>\n              </div>\n              <div class="ps-prod-metrics">\n                <div class="ps-prod-metrics-title">Your Revenue Model: Cash Flow Engine</div>\n                <div class="ps-prod-metric">\n        <span class="ps-prod-metric-label">Target Customer</span>\n        <span class="ps-prod-metric-value">20-200 employees</span>\n      </div><div class="ps-prod-metric">\n        <span class="ps-prod-metric-label">Turn Time</span>\n        <span class="ps-prod-metric-value ps-prod-metric-hl">3-6 months</span>\n      </div><div class="ps-prod-metric">\n        <span class="ps-prod-metric-label">Avoid</span>\n        <span class="ps-prod-metric-value">“Long project death”</span>\n      </div><div class="ps-prod-metric">\n        <span class="ps-prod-metric-label">Revenue Type</span>\n        <span class="ps-prod-metric-value">SME Cash Flow</span>\n      </div>\n              </div>\n            </div>\n            <div class="ps-prod-card">\n              <div class="ps-prod-info">\n                <span class="ps-prod-badge">The “Strategic Wedge”</span>\n                <h3>MES</h3>\n                <p class="ps-prod-desc">The <strong>“Reverse Cut” Strategy.</strong> You don’t have to rip and replace their existing ERP—even if it’s a global brand. Sell MES as the “Shop Floor Enforcer” that fixes inventory accuracy and OEE tracking. Appeals to owners tired of “Shadow Excel” wanting real-time visibility.</p>\n                <ul class="ps-prod-features"><li><svg viewBox="0 0 24 24" fill="none" stroke-width="2" aria-hidden="true"><polyline points="20 6 9 17 4 12"/></svg><span>“Keep your current ERP for Finance. Use Digiwin for the factory floor.”</span></li><li><svg viewBox="0 0 24 24" fill="none" stroke-width="2" aria-hidden="true"><polyline points="20 6 9 17 4 12"/></svg><span>Premium rates for process consulting & hardware integration</span></li><li><svg viewBox="0 0 24 24" fill="none" stroke-width="2" aria-hidden="true"><polyline points="20 6 9 17 4 12"/></svg><span>Once you control shop floor data, client cannot leave</span></li><li><svg viewBox="0 0 24 24" fill="none" stroke-width="2" aria-hidden="true"><polyline points="20 6 9 17 4 12"/></svg><span><strong>“Trojan Horse”:</strong> MES → WMS → AIoT → T100/iGP</span></li></ul>\n                <a href="/products/mes/" class="ps-prod-link">Learn more about MES <svg viewBox="0 0 24 24" fill="none" stroke-width="2" aria-hidden="true"><line x1="5" y1="12" x2="19" y2="12"/><polyline points="12 5 19 12 12 19"/></svg></a>\n              </div>\n              <div class="ps-prod-metrics">\n                <div class="ps-prod-metrics-title">Your Revenue Model: Sticky Recurring</div>\n                <div class="ps-prod-metric">\n        <span class="ps-prod-metric-label">Entry Point</span>\n        <span class="ps-prod-metric-value ps-prod-metric-hl">~1M THB (vs. 5M+ ERP)</span>\n      </div><div class="ps-prod-metric">\n        <span class="ps-prod-metric-label">Timeline</span>\n        <span class="ps-prod-metric-value ps-prod-metric-hl">3-6 months (vs. 18mo)</span>\n      </div><div class="ps-prod-metric">\n        <span class="ps-prod-metric-label">Retention</span>\n        <span class="ps-prod-metric-value">Higher barrier to exit</span>\n      </div><div class="ps-prod-metric">\n        <span class="ps-prod-metric-label">Revenue Type</span>\n        <span class="ps-prod-metric-value">Retention Asset</span>\n      </div>\n              </div>\n            </div>\n            <div class="ps-prod-card">\n              <div class="ps-prod-info">\n                <span class="ps-prod-badge">The “Value Multipliers”</span>\n                <h3>AIoT & WMS: Lock-In Layers</h3>\n                <p class="ps-prod-desc"><strong>WMS — “Zero Ghost Inventory”:</strong> Sell to owners terrified of theft or audit failure. Digitizes physical movement of goods. <strong>AIoT — “Future Proofing”:</strong> Shows you have capability to connect machines (PLCs) directly to ERP. Differentiates you from accounting firms.</p>\n                <ul class="ps-prod-features"><li><svg viewBox="0 0 24 24" fill="none" stroke-width="2" aria-hidden="true"><polyline points="20 6 9 17 4 12"/></svg><span>Hardware/middleware resale opportunity (handhelds, sensors)</span></li><li><svg viewBox="0 0 24 24" fill="none" stroke-width="2" aria-hidden="true"><polyline points="20 6 9 17 4 12"/></svg><span>Recurring data monitoring & optimization services</span></li><li><svg viewBox="0 0 24 24" fill="none" stroke-width="2" aria-hidden="true"><polyline points="20 6 9 17 4 12"/></svg><span>Solves “system says 100, shelf has 50” problem</span></li><li><svg viewBox="0 0 24 24" fill="none" stroke-width="2" aria-hidden="true"><polyline points="20 6 9 17 4 12"/></svg><span><strong>Physical lock-in:</strong> Scanners & sensors = 10+ year relationships</span></li></ul>\n                <a href="/products/aiot/" class="ps-prod-link">Learn more about AIoT & WMS <svg viewBox="0 0 24 24" fill="none" stroke-width="2" aria-hidden="true"><line x1="5" y1="12" x2="19" y2="12"/><polyline points="12 5 19 12 12 19"/></svg></a>\n              </div>\n              <div class="ps-prod-metrics">\n                <div class="ps-prod-metrics-title">Your Revenue Model: Differentiation</div>\n                <div class="ps-prod-metric">\n        <span class="ps-prod-metric-label">Physical Integration</span>\n        <span class="ps-prod-metric-value ps-prod-metric-hl">Ultimate lock-in</span>\n      </div><div class="ps-prod-metric">\n        <span class="ps-prod-metric-label">Hardware Drag</span>\n        <span class="ps-prod-metric-value">Scanners, sensors, PLCs</span>\n      </div><div class="ps-prod-metric">\n        <span class="ps-prod-metric-label">Client Lifetime</span>\n        <span class="ps-prod-metric-value ps-prod-metric-hl">10+ years</span>\n      </div><div class="ps-prod-metric">\n        <span class="ps-prod-metric-label">Revenue Type</span>\n        <span class="ps-prod-metric-value">Differentiation Asset</span>\n      </div>\n              </div>\n            </div>\n      </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Lifecycle: Land & Expand"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Lifecycle: Land & Expand: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Lifecycle: Land & Expand: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="ps-lc-section">\n      <div class="ps-lc-wave" aria-hidden="true"></div>\n      <div class="ps-lc-inner">\n        <div class="ps-lc-header">\n          <span class="ps-lc-label">CUSTOMER LIFECYCLE MANAGEMENT</span>\n          <h2 class="ps-lc-title">The “Land and Expand” Strategy</h2>\n          <p class="ps-lc-subtitle">You’re not selling software. You’re executing a 4-phase account takeover strategy.</p>\n        </div>\n        <div class="ps-lc-phases">\n                <div class="ps-lc-phase ps-lc-phase-1">\n                  <div class="ps-lc-num" style="background:#00AFF0">1</div>\n                  <h3>Land</h3>\n                  <div class="ps-lc-products">iGP (Volume) or MES (Reverse Cut)</div>\n                  <p>Entry point with immediate value. Fast project, quick cash.</p>\n                  <div class="ps-lc-revenue">Project fees + License</div>\n                </div><div class="ps-lc-arrow"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" aria-hidden="true"><line x1="5" y1="12" x2="19" y2="12"/><polyline points="12 5 19 12 12 19"/></svg></div>\n                <div class="ps-lc-phase ps-lc-phase-2">\n                  <div class="ps-lc-num" style="background:#10b981">2</div>\n                  <h3>Stabilize</h3>\n                  <div class="ps-lc-products">WMS</div>\n                  <p>Control inventory accuracy. Solve “Ghost Inventory” pain.</p>\n                  <div class="ps-lc-revenue">Project + Hardware</div>\n                </div><div class="ps-lc-arrow"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" aria-hidden="true"><line x1="5" y1="12" x2="19" y2="12"/><polyline points="12 5 19 12 12 19"/></svg></div>\n                <div class="ps-lc-phase ps-lc-phase-3">\n                  <div class="ps-lc-num" style="background:#f59e0b">3</div>\n                  <h3>Expand</h3>\n                  <div class="ps-lc-products">T100 ERP</div>\n                  <p>Scale to enterprise. High-value project revenue.</p>\n                  <div class="ps-lc-revenue">Enterprise project</div>\n                </div><div class="ps-lc-arrow"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" aria-hidden="true"><line x1="5" y1="12" x2="19" y2="12"/><polyline points="12 5 19 12 12 19"/></svg></div>\n                <div class="ps-lc-phase ps-lc-phase-4">\n                  <div class="ps-lc-num" style="background:#8b5cf6">4</div>\n                  <h3>Lock</h3>\n                  <div class="ps-lc-products">AIoT</div>\n                  <p>Physical integration = permanent retention.</p>\n                  <div class="ps-lc-revenue">Subscription + Data</div>\n                </div>\n        </div>\n        <div class="ps-lc-proof">\n          <p><strong>This isn’t just software—it’s a Customer Lifecycle Management strategy that compounds revenue over years.</strong></p>\n        </div>\n      </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Reverse Cut Strategy"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Reverse Cut Strategy: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Reverse Cut Strategy: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="ps-rc-section">\n      <div class="ps-rc-inner">\n        <div class="ps-rc-header">\n          <span class="ps-rc-label">THE REVERSE CUT STRATEGY</span>\n          <h2 class="ps-rc-title">How to Win Enterprise ERP Accounts</h2>\n          <p class="ps-rc-subtitle">Don’t fight the castle at the front gate. Enter through the factory door with MES, make yourself indispensable, and win the ERP business from the inside out.</p>\n        </div>\n        <div class="ps-rc-grid">\n            <div class="ps-rc-phase">\n              <div class="ps-rc-phase-hd">\n                <span class="ps-rc-tag">Phase 1</span>\n                <h3>The Wedge</h3>\n              </div>\n              <p>Sell MES as the “Shop Floor Enforcer” that fixes production data accuracy. <strong>“Keep their current ERP for Finance. Use Digiwin for the factory floor.”</strong></p>\n              <div class="ps-rc-exp">\n                <span class="ps-rc-exp-label">Client Experience:</span>\n                <span class="ps-rc-exp-quote">“Finally, I can see what’s actually happening on the floor.”</span>\n              </div>\n            </div>\n            <div class="ps-rc-phase">\n              <div class="ps-rc-phase-hd">\n                <span class="ps-rc-tag">Phase 2</span>\n                <h3>The Contrast</h3>\n              </div>\n              <p>Client realizes Digiwin MES is flexible and “manufacturing-native” while their legacy ERP is rigid. The “integration tax” of maintaining two systems becomes annoying.</p>\n              <div class="ps-rc-exp">\n                <span class="ps-rc-exp-label">Client Experience:</span>\n                <span class="ps-rc-exp-quote">“Why is updating our legacy ERP so painful when Digiwin just works?”</span>\n              </div>\n            </div>\n            <div class="ps-rc-phase">\n              <div class="ps-rc-phase-hd">\n                <span class="ps-rc-tag">Phase 3</span>\n                <h3>The Replacement</h3>\n              </div>\n              <p>When legacy ERP needs upgrade or license renewal, propose T100. <strong>“You already run your factory on Digiwin. Why not run your books on it too?”</strong></p>\n              <div class="ps-rc-exp">\n                <span class="ps-rc-exp-label">Client Experience:</span>\n                <span class="ps-rc-exp-quote">“Let’s just consolidate everything on Digiwin.”</span>\n              </div>\n            </div>\n        </div>\n        <div class="ps-rc-comparison">\n          <h4>Why It Works: Lower Risk Threshold</h4>\n          <table class="ps-rc-table">\n            <caption class="sr-only">Comparison of Full ERP Replacement versus MES Reverse Cut entry approach</caption>\n            <thead><tr><th scope="col">Metric</th><th scope="col">Full ERP Replacement</th><th scope="col">MES Entry (Reverse Cut)</th></tr></thead>\n            <tbody>\n              <tr>\n                <td>Budget</td>\n                <td class="ps-rc-old" data-label="Full ERP">5M+ THB</td>\n                <td class="ps-rc-new" data-label="Reverse Cut">~1M THB</td>\n              </tr>\n              <tr>\n                <td>Timeline</td>\n                <td class="ps-rc-old" data-label="Full ERP">9-18 months</td>\n                <td class="ps-rc-new" data-label="Reverse Cut">3-6 months</td>\n              </tr>\n              <tr>\n                <td>Disruption</td>\n                <td class="ps-rc-old" data-label="Full ERP">High (rip-and-replace)</td>\n                <td class="ps-rc-new" data-label="Reverse Cut">Low (overlay)</td>\n              </tr>\n              <tr>\n                <td>Client Risk</td>\n                <td class="ps-rc-old" data-label="Full ERP">High</td>\n                <td class="ps-rc-new" data-label="Reverse Cut">Low</td>\n              </tr>\n            </tbody>\n          </table>\n        </div>\n      </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Competitive Positioning"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Competitive Positioning: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Competitive Positioning: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="ps-comp-section" data-particles>\n      <div class="ps-comp-inner">\n        <div class="ps-comp-header">\n          <span class="ps-comp-label">COMPETITIVE POSITIONING</span>\n          <h2 class="ps-comp-title">Your Talking Points for Sales Conversations</h2>\n          <p class="ps-comp-subtitle">How to position DigiWin against the competition in any sales conversation.</p>\n        </div>\n        <div class="ps-comp-grid">\n            <div class="ps-comp-card">\n              <div class="ps-comp-tag">vs. Mid-Market ERP Systems</div>\n              <h3>“They Stop at the Office Door”</h3>\n              <div class="ps-comp-points"><div class="ps-comp-point"><strong>The Manufacturing Void:</strong> Mid-market ERP systems treat manufacturing as simple kitting. They struggle with Thai production realities—mold management, regrind (scrap reuse), complex sub-contracting loops. We handle these natively.</div><div class="ps-comp-point"><strong>The Phantom Problem:</strong> Generic ERPs force you to create thousands of ‘dummy’ inventory transactions for Phantom BOMs. Digiwin manages this automatically, keeping warehouse data clean.</div><div class="ps-comp-point"><strong>The Cost of “Good Enough”:</strong> To make generic ERP handle deep manufacturing, you need 3rd-party add-ons. This increases TCO and creates “version lock” risks. Digiwin’s MES/WMS are native.</div>\n              </div>\n              <div class="ps-comp-use-when"><strong>Use when:</strong> Client has a mid-market ERP but complains about production visibility.</div>\n            </div>\n            <div class="ps-comp-card">\n              <div class="ps-comp-tag">vs. Enterprise ERP Giants</div>\n              <h3>“Tier-1 Capability, No German Logic”</h3>\n              <div class="ps-comp-points"><div class="ps-comp-point"><strong>Agility vs. Rigidity:</strong> Enterprise ERP systems often enforce rigid, linear processes that break when rush orders arrive or machines fail. Digiwin T100 handles urgent order splitting and mid-production changes without rolling back schedules.</div><div class="ps-comp-point"><strong>Total Cost Advantage:</strong> We deliver 90% of Tier-1 capability at ~70% of the price. Shorter implementation (6-9 months vs. 12-18 months) using pre-built Automotive/Electronics templates.</div><div class="ps-comp-point"><strong>Transparent Pricing:</strong> No audit risks, no spiraling “named user” costs. Digiwin offers transparent pricing for high-volume shop floor users.</div>\n              </div>\n              <div class="ps-comp-use-when"><strong>Use when:</strong> Client is evaluating enterprise ERP but has budget concerns or flexibility needs.</div>\n            </div>\n            <div class="ps-comp-card">\n              <div class="ps-comp-tag">vs. Local Vendors & Open-Source</div>\n              <h3>“Scale Without the Dead End”</h3>\n              <div class="ps-comp-points"><div class="ps-comp-point"><strong>The Vanishing Vendor:</strong> Local ERPs are 30% cheaper but lack R&D budget to survive the next tech shift (AI, IoT). Digiwin is publicly listed (300378) with <span class="dw-years">44</span> years of history and Foxconn backing.</div><div class="ps-comp-point"><strong>The Feature Ceiling:</strong> Open-source ERP hits a complexity wall when you need real-time machine integration (IoT) or traceability for ISO/IATF audits. Digiwin has these built-in.</div><div class="ps-comp-point"><strong>Financial Credibility:</strong> Your bank and auditors know Digiwin. Using T100 or iGP helps with IPO preparation and loan approvals in ways custom-built local software cannot.</div>\n              </div>\n              <div class="ps-comp-use-when"><strong>Use when:</strong> Client is tempted by low-cost local options or open-source alternatives.</div>\n            </div>\n        </div>\n        <div class="ps-comp-ace">\n          <div class="ps-comp-ace-label">THE ACE CARD</div>\n          <p class="ps-comp-ace-quote">“Enterprise ERP manages your General Ledger. Local software manages your Invoices. <strong>Digiwin manages your Factory Floor.</strong> We are the only ones who understand that the physical reality of a Thai production line doesn’t always match the accounting rules.”</p>\n        </div>\n      </div>\n    </div>\n    <script>/**\n * DigiWin 数据洋流 (Data Ocean Current)\n *\n * Recreates the brand kit\'s signature visual: a 3D dot-grid surface\n * with dramatic rolling wave crests, viewed from a low angle.\n * Reference: DigiWin 2025 Annual Report cover, brand kit pp.61-68.\n *\n * Usage:\n *   <section data-particles>              — subtle on light bg (default)\n *   <section data-particles="bold">       — vivid on dark navy bg\n *   <section data-particles="medium">     — moderate visibility\n *\n * WordPress: wp_enqueue_script or Code Module. Self-initializing.\n */\n\n(function () {\n    \'use strict\';\n\n    var reducedMotion = window.matchMedia(\'(prefers-reduced-motion: reduce)\').matches;\n    var PI2 = Math.PI * 2;\n\n    // ── Brand colors (RGB) ──────────────────────────────────────────\n    var BLUE = [0, 175, 240];   // #00AFF0 Smart Blue\n    var CYAN = [0, 230, 255];   // #00E6FF Cyan accent\n\n    // ── Presets ─────────────────────────────────────────────────────\n    var PRESETS = {\n        light: {\n            frontOpacity: 0.18,   // visible but not distracting on white/light backgrounds\n            backOpacity: 0.03,\n            frontRadius: 3.5,\n            backRadius: 0.5,\n            color: BLUE,\n            colorAlt: CYAN,\n            altRatio: 0.10\n        },\n        subtle: {\n            frontOpacity: 0.30,   // foreground dot opacity\n            backOpacity: 0.04,    // distant dot opacity\n            frontRadius: 4.5,     // foreground dot size (px)\n            backRadius: 0.6,      // distant dot size (px)\n            color: BLUE,\n            colorAlt: CYAN,\n            altRatio: 0.12\n        },\n        medium: {\n            frontOpacity: 0.45,\n            backOpacity: 0.06,\n            frontRadius: 5.0,\n            backRadius: 0.8,\n            color: BLUE,\n            colorAlt: CYAN,\n            altRatio: 0.18\n        },\n        bold: {\n            frontOpacity: 0.60,\n            backOpacity: 0.10,\n            frontRadius: 5.5,\n            backRadius: 1.0,\n            color: CYAN,\n            colorAlt: BLUE,\n            altRatio: 0.25\n        }\n    };\n\n    // ── Utility ─────────────────────────────────────────────────────\n    function lerp(a, b, t) { return a + (b - a) * t; }\n\n    // ── DataOcean class ─────────────────────────────────────────────\n    function DataOcean(el) {\n        this.el = el;\n        this.canvas = null;\n        this.ctx = null;\n        this.w = 0;\n        this.h = 0;\n        this.dpr = Math.min(window.devicePixelRatio || 1, 2);\n        this.visible = false;\n        this.raf = null;\n        this.time = 0;\n        this.resizeTimer = null;\n        this.colors = null; // pre-assigned per grid point\n\n        this.opts = this._parseOpts();\n        this._setup();\n        this._buildColors();\n        this._observe();\n\n        if (!reducedMotion) {\n            this._loop();\n        } else {\n            this.visible = true;\n            this._draw(0);\n        }\n    }\n\n    DataOcean.prototype._parseOpts = function () {\n        var name = this.el.getAttribute(\'data-particles\') || \'subtle\';\n        if (name === \'\' || name === \'true\') name = \'subtle\';\n        return PRESETS[name] || PRESETS.subtle;\n    };\n\n    DataOcean.prototype._setup = function () {\n        var c = document.createElement(\'canvas\');\n        c.setAttribute(\'aria-hidden\', \'true\');\n        c.style.cssText = \'position:absolute;inset:0;width:100%;height:100%;pointer-events:none;z-index:0;\';\n        var pos = getComputedStyle(this.el).position;\n        if (pos === \'static\') this.el.style.position = \'relative\';\n        this.el.style.overflow = \'hidden\';\n        this.el.insertBefore(c, this.el.firstChild);\n        this.canvas = c;\n        this.ctx = c.getContext(\'2d\');\n        this._resize();\n\n        var self = this;\n        window.addEventListener(\'resize\', function () {\n            clearTimeout(self.resizeTimer);\n            self.resizeTimer = setTimeout(function () {\n                self._resize();\n                self._buildColors();\n            }, 200);\n        });\n    };\n\n    DataOcean.prototype._resize = function () {\n        var r = this.el.getBoundingClientRect();\n        this.w = r.width;\n        this.h = r.height;\n        this.canvas.width = this.w * this.dpr;\n        this.canvas.height = this.h * this.dpr;\n        this.ctx.setTransform(this.dpr, 0, 0, this.dpr, 0, 0);\n    };\n\n    // Grid: ~55 cols × ~35 rows. Pre-assign a color to each dot.\n    DataOcean.prototype._buildColors = function () {\n        var cols = Math.min(65, Math.ceil(this.w / 22) + 4);\n        var rows = 35;\n        this._cols = cols;\n        this._rows = rows;\n        var n = cols * rows;\n        this.colors = new Array(n);\n        var alt = this.opts.altRatio;\n        for (var i = 0; i < n; i++) {\n            this.colors[i] = Math.random() < alt ? this.opts.colorAlt : this.opts.color;\n        }\n    };\n\n    DataOcean.prototype._observe = function () {\n        var self = this;\n        if (\'IntersectionObserver\' in window) {\n            this._obs = new IntersectionObserver(function (e) {\n                self.visible = e[0].isIntersecting;\n            }, { rootMargin: \'150px 0px\' });\n            this._obs.observe(this.el);\n        } else {\n            this.visible = true;\n        }\n    };\n\n    DataOcean.prototype._loop = function () {\n        var self = this;\n        var last = 0;\n        (function tick(ts) {\n            self.raf = requestAnimationFrame(tick);\n            if (!self.visible) return;\n            if (ts - last < 30) return; // ~30 fps\n            last = ts;\n            self.time += 0.006;\n            self._draw(self.time);\n        })(0);\n    };\n\n    /**\n     * ── Core renderer ───────────────────────────────────────────────\n     *\n     * Approach: Think of a flat grid of dots on a table, viewed from a\n     * low angle. The table surface undulates with large rolling waves.\n     *\n     * "depth" goes from 0 (nearest / bottom of screen) to 1 (farthest /\n     * top area). Everything scales with depth:\n     *   - dot size shrinks\n     *   - dot opacity fades\n     *   - vertical row spacing compresses (perspective foreshortening)\n     *   - horizontal dot spacing tightens\n     *   - wave amplitude diminishes\n     *\n     * The wave function creates 2-3 visible rolling crests that sweep\n     * diagonally across the surface — matching the annual report cover.\n     */\n    DataOcean.prototype._draw = function (t) {\n        var ctx = this.ctx;\n        var w = this.w;\n        var h = this.h;\n        var opts = this.opts;\n        var cols = this._cols;\n        var rows = this._rows;\n\n        ctx.clearRect(0, 0, w, h);\n\n        // ── Perspective layout ──────────────────────────────────────\n        //\n        // The wave occupies the bottom ~55% of the section.\n        // "horizon" is where distant rows converge (top of wave area).\n        // "ground" is the bottom edge of the section.\n\n        var ground = h + 10;               // bottom edge (+ small overflow)\n        var horizon = h * 0.35;            // where distant dots vanish toward\n        var totalSpan = ground - horizon;   // vertical pixel range for the wave\n\n        var idx = 0;\n\n        // Draw back-to-front for correct visual layering\n        for (var row = rows - 1; row >= 0; row--) {\n\n            // ── Depth (0 = near/bottom, 1 = far/top) ───────────────\n            var depth = row / (rows - 1);\n\n            // Non-linear depth mapping: compress more toward horizon\n            // This creates the "accelerating compression" of perspective\n            var mappedDepth = Math.pow(depth, 0.55);\n\n            // Screen Y baseline for this row (no wave yet)\n            var baseY = ground - mappedDepth * totalSpan;\n\n            // ── Per-row properties (lerp by depth) ──────────────────\n            var dotR = lerp(opts.frontRadius, opts.backRadius, depth);\n            var dotA = lerp(opts.frontOpacity, opts.backOpacity, depth);\n            var colSpacing = lerp(w / (cols - 4), w / (cols + 15), depth);\n\n            // Slight horizontal offset per row (creates diagonal sweep)\n            var rowShift = depth * w * 0.12;\n\n            // ── Wave: two layers for organic rolling feel ───────────\n            //\n            // Primary wave: large rolling crests (creates the signature look)\n            // Secondary wave: smaller ripple for naturalism\n            //\n            // Wave amplitude is BIG near foreground and diminishes with depth.\n            // This is what makes the crests dramatically visible.\n\n            var waveScale = (1 - depth * 0.75); // waves diminish into distance\n            var amp1 = 70 * waveScale;           // primary crest amplitude (px)\n            var amp2 = 25 * waveScale;           // secondary ripple\n\n            for (var col = 0; col < cols; col++) {\n                // Screen X\n                var screenX = col * colSpacing - rowShift + colSpacing * 0.5;\n\n                // Wrap X for seamless edge handling\n                if (screenX < -30 || screenX > w + 30) { idx++; continue; }\n\n                // ── Wave displacement ───────────────────────────────\n                //\n                // The primary wave sweeps diagonally (uses both col and row).\n                // freq values tuned so ~2 full crests are visible across width.\n\n                var worldX = col * 24; // stable world-space coordinate for wave\n                var worldZ = row * 18;\n\n                var wave = amp1 * Math.sin(\n                    worldX * 0.0065 + worldZ * 0.012 + t * 0.9\n                );\n                wave += amp2 * Math.sin(\n                    worldX * 0.013 - worldZ * 0.008 + t * 0.55 + 1.8\n                );\n\n                var screenY = baseY - wave;\n\n                // Skip if outside visible area\n                if (screenY < -15 || screenY > h + 15) { idx++; continue; }\n\n                // ── Draw dot ────────────────────────────────────────\n                var c = this.colors[idx % this.colors.length];\n                ctx.beginPath();\n                ctx.arc(screenX, screenY, dotR, 0, PI2);\n                ctx.fillStyle = \'rgba(\' + c[0] + \',\' + c[1] + \',\' + c[2] + \',\' + dotA + \')\';\n                ctx.fill();\n\n                idx++;\n            }\n        }\n    };\n\n    DataOcean.prototype.destroy = function () {\n        if (this.raf) cancelAnimationFrame(this.raf);\n        if (this._obs) this._obs.disconnect();\n        if (this.canvas && this.canvas.parentNode) {\n            this.canvas.parentNode.removeChild(this.canvas);\n        }\n    };\n\n    // ── Auto-init ───────────────────────────────────────────────────\n    function init() {\n        var els = document.querySelectorAll(\'[data-particles]\');\n        var inst = [];\n        for (var i = 0; i < els.length; i++) inst.push(new DataOcean(els[i]));\n\n        window.DigiWinParticleOcean = {\n            instances: inst,\n            DataOcean: DataOcean,\n            refresh: function () {\n                for (var j = 0; j < inst.length; j++) inst[j].destroy();\n                inst = [];\n                var els2 = document.querySelectorAll(\'[data-particles]\');\n                for (var k = 0; k < els2.length; k++) inst.push(new DataOcean(els2[k]));\n                this.instances = inst;\n            }\n        };\n    }\n\n    if (document.readyState === \'loading\') {\n        document.addEventListener(\'DOMContentLoaded\', init);\n    } else {\n        init();\n    }\n})();\n</script><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"CTA: See the Economics"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"CTA: See the Economics: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"CTA: See the Economics: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="ps-cta-section">\n    <div class="ps-cta-super-d" aria-hidden="true"></div>\n    <div class="ps-cta-wave-flow" aria-hidden="true"></div>\n    <div class="ps-cta-container">\n      <h2 class="ps-cta-title">Now See the Actual Economics</h2>\n      <p class="ps-cta-subtitle">You’ve seen the arsenal. Now see the math—margins, recurring revenue, and multi-year projections for your business.</p>\n      <div class="ps-cta-btn-row">\n        <a href="/partner-program/economics/" class="ps-cta-btn ps-cta-btn--primary">See Partner Economics →</a>\n        <a href="/demo/" class="ps-cta-btn ps-cta-btn--ghost">Let’s Talk</a>\n      </div>\n    </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- /wp:divi/placeholder -->',
  post_modified = NOW(),
  post_modified_gmt = UTC_TIMESTAMP()
WHERE ID = 100560;

-- Step 2: Update Divi 5 custom CSS
DELETE FROM wp_postmeta WHERE post_id = 100560 AND meta_key = '_et_pb_custom_css';
INSERT INTO wp_postmeta (post_id, meta_key, meta_value) VALUES (100560, '_et_pb_custom_css', '/* === GLOBAL DIVI THEME RESET === */\n.et_pb_section,.et_pb_row,.et_pb_column,.et_pb_code,.et_pb_code_inner{font-family:\'Noto Sans\',sans-serif !important;font-weight:400 !important;font-size:16px !important;color:#333 !important}\n.et_pb_section h1,.et_pb_section h2,.et_pb_section h3,.et_pb_section h4,.et_pb_section h5,.et_pb_section h6{padding-bottom:0 !important}\n.et_pb_section:not([class*=\'tb_body\']){overflow:hidden !important;margin:0 !important}\n.et_pb_row:not([class*=\'tb_body\']){max-width:100% !important;width:100% !important;padding:0 !important;margin-top:0 !important;margin-bottom:0 !important;gap:0 !important}\n.et_pb_column:not([class*=\'tb_body\']){padding:0 !important;margin:0 !important;gap:0 !important}\n.et_pb_section .et_pb_row .et_pb_column .et_pb_text.et_pb_module{margin:0 !important;padding:0 !important}\n.section-title{line-height:1.6;-webkit-font-smoothing:auto}\n.section-subtitle{margin-left:auto;margin-right:auto;line-height:1.6}\n/* fade-in / scroll-fade-in: always visible (no JS scroll observer in Divi) */\n.fade-in,.scroll-fade-in{opacity:1 !important;transform:none !important}\n/* === DIVI MOBILE ROW PADDING OVERRIDE === */\n/* Divi injects: @media(max-width:640px){.et_pb_section .et_pb_row{padding:0 24px !important}}\n   Specificity 0,2,0. We use .et_pb_row.et_pb_row (0,2,0 doubled = 0,2,0 still, but\n   .et_pb_section prefix pushes us to 0,3,0) to beat it. */\n@media(max-width:640px){\n  .et_pb_section .et_pb_row.et_pb_row{padding:0 !important}\n}\n/* === MOBILE TOUCH TARGET RESET (WCAG 2.5.8 — 44px minimum) === */\n@media(max-width:768px){\n  a:not(.dw-logo):not(.dw-nav-link):not([class*="btn"]):not([class*="cta"]):not([class*="Cta"]),\n  input:not([type="hidden"]):not([type="checkbox"]):not([type="radio"]),\n  select,textarea{min-height:44px}\n  a:not(.dw-logo):not(.dw-nav-link):not([class*="btn"]):not([class*="cta"]):not([class*="Cta"]){display:inline-flex;align-items:center}\n  input:not([type="hidden"]):not([type="checkbox"]):not([type="radio"]){min-height:44px}\n}\n\n@keyframes fadeIn{from{opacity:0}to{opacity:1}}\n@keyframes slide-up{from{opacity:0;transform:translateY(30px)}to{opacity:1;transform:translateY(0)}}\n@keyframes grain{0%,100%{transform:translate(0,0)}10%{transform:translate(-2%,-2%)}20%{transform:translate(2%,2%)}30%{transform:translate(-1%,1%)}40%{transform:translate(1%,-1%)}50%{transform:translate(-2%,2%)}60%{transform:translate(2%,-2%)}70%{transform:translate(-1%,-1%)}80%{transform:translate(1%,1%)}90%{transform:translate(-2%,2%)}}\n@keyframes dw-wave-drift{0%{transform:translateX(0)}100%{transform:translateX(-50%)}}\n@keyframes dw-scroll{0%{transform:translateX(0)}100%{transform:translateX(-50%)}}\n/* === PARTNER SOLUTIONS HERO === */\n.ps-hero-section{background:linear-gradient(135deg,#000432 0%,#000864 50%,#001080 100%);padding:140px 24px 100px;position:relative;overflow:hidden;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px}\n.ps-hero-section::before{content:\'\';position:absolute;inset:0;background-image:radial-gradient(circle,rgba(255,255,255,0.03) 1.5px,transparent 1.5px);background-size:60px 60px;pointer-events:none;z-index:0}\n.ps-hero-grain::before{content:\'\';position:absolute;top:0;left:0;right:0;bottom:0;background-image:url("data:image/svg+xml,%3Csvg viewBox=\'0 0 400 400\' xmlns=\'http://www.w3.org/2000/svg\'%3E%3Cfilter id=\'n\'%3E%3CfeTurbulence type=\'fractalNoise\' baseFrequency=\'0.9\' numOctaves=\'4\' stitchTiles=\'stitch\'/%3E%3C/filter%3E%3Crect width=\'100%25\' height=\'100%25\' filter=\'url(%23n)\'/%3E%3C/svg%3E");opacity:0.03;pointer-events:none;z-index:1}\n.ps-hero-grain{position:absolute;inset:0;z-index:1;opacity:0.16}\n.ps-hero-d-bg{position:absolute;top:50%;right:auto;left:50%;width:80%;min-height:80vh;background:url("data:image/svg+xml;base64,") no-repeat center center;background-size:contain;transform:translate(-50%, -50%);opacity:0.08;pointer-events:none;z-index:0}\n.ps-hero-dot-overlay{position:absolute;inset:0;background-image:radial-gradient(circle,rgba(255,255,255,0.03) 1.5px,transparent 1.5px);background-size:60px 60px;pointer-events:none;z-index:1}\n.ps-hero-inner{max-width:900px;margin:0 auto;position:relative;z-index:3}\n.ps-hero-breadcrumb{font-family:\'Noto Sans\',sans-serif;font-size:14px;color:rgba(255,255,255,0.85);margin-bottom:24px}\n.ps-hero-breadcrumb a{color:rgba(255,255,255,0.85);text-decoration:none;transition:color 0.2s}\n.ps-hero-breadcrumb a:hover{color:#00AFF0}\n.ps-hero-breadcrumb span{margin:0 8px}\n.ps-hero-title{font-family:\'Noto Sans\',sans-serif;font-size:clamp(36px,5vw,52px);font-weight:700;color:#fff;line-height:1.15;margin:0 0 24px;padding:0}\n.ps-hero-hl{color:#00AFF0}\n.ps-hero-subtitle{font-family:\'Noto Sans\',sans-serif;font-size:20px;font-weight:400;color:rgba(255,255,255,0.85);line-height:1.7;max-width:700px;margin:0 0 48px;padding:0}\n.ps-hero-stats{display:grid;grid-template-columns:repeat(3,1fr);gap:32px;padding-top:40px;border-top:1px solid rgba(255,255,255,0.1)}\n.ps-hero-stat{text-align:center}\n.ps-hero-stat-value{font-family:\'Noto Sans\',sans-serif;font-size:48px;font-weight:700;color:#0369a1;line-height:1;margin-bottom:8px}\n.ps-hero-stat-label{font-size:14px;color:rgba(255,255,255,0.85);line-height:1.4}\n@media(max-width:1024px){\n  .ps-hero-section{padding:120px 24px 80px}\n  .ps-hero-stats{grid-template-columns:1fr;gap:24px}\n}\n@media(max-width:768px){\n  .ps-hero-section{padding:100px 20px 60px}\n  .ps-hero-stat-value{font-size:36px}\n}\n@media(prefers-reduced-motion:reduce){.ps-hero-breadcrumb a{transition:none !important}}\n/* === PRODUCTS SECTION (S2) === */\n.ps-prod-section{padding:100px 24px;background:#fff;position:relative;overflow:hidden;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px}\n.ps-prod-scene{position:absolute;inset:0;pointer-events:none;z-index:0}.ps-prod-scene svg{width:100%;height:100%;position:absolute;top:0;left:0;opacity:0.20}\n.ps-prod-wave-left{position:absolute;top:0;left:0;bottom:0;width:200px;opacity:0.08;background:linear-gradient(90deg,rgba(0,175,240,0.15) 0%,transparent 100%);pointer-events:none;z-index:0}\n.ps-prod-inner{max-width:1200px;margin:0 auto;position:relative;z-index:2}\n.ps-prod-header{text-align:center;margin-bottom:60px}\n.ps-prod-title{font-family:\'Noto Sans\',sans-serif;font-size:40px;font-weight:700;color:#000864;line-height:1.6;margin:0 0 16px;padding:0}\n.ps-prod-subtitle{font-family:\'Noto Sans\',sans-serif;font-size:18px;font-weight:400;color:#5b6b80;line-height:1.6;margin:0 auto;padding:0}\n.ps-prod-card{display:grid;grid-template-columns:1fr 1fr;gap:48px;background:#fff;border:1px solid #e2e8f0;border-radius:24px;padding:48px;margin-bottom:32px;transition:all 0.3s ease}\n.ps-prod-card:hover{border-color:#00AFF0;box-shadow:0 12px 48px rgba(0,175,240,0.12);transform:none}\n.ps-prod-card:nth-child(even){direction:rtl}\n.ps-prod-card:nth-child(even)>*{direction:ltr}\n.ps-prod-info{display:flex;flex-direction:column}\n.ps-prod-badge{display:inline-flex;align-items:center;gap:8px;background:linear-gradient(135deg,#00AFF0,#003CC8);color:#fff;padding:8px 16px;border-radius:50px;font-size:13px;font-weight:600;width:fit-content;margin-bottom:20px}\n.ps-prod-card h3{font-family:\'Noto Sans\',sans-serif;font-size:28px;font-weight:700;color:#000864;line-height:1.6;margin:0 0 16px;padding:0}\n.ps-prod-desc{font-size:16px;color:#5b6b80;line-height:1.7;margin:0 0 24px;padding:0}\n.ps-prod-desc strong{color:#000864}\n.ps-prod ul,.ps-prod ol{list-style:none !important;padding:0 !important;margin:0 !important}.ps-prod li{list-style:none !important}.ps-prod li::before{display:none !important}\n.ps-prod-features{margin:0 0 24px !important}\n.ps-prod-features li{display:flex !important;align-items:flex-start;gap:12px;padding:10px 0;border-bottom:1px solid #f1f5f9}\n.ps-prod-features li:last-child{border-bottom:none}\n.ps-prod-