ba(255,255,255,0.15);border-color:#fff}\n.ps-cta-btn-row{display:flex;gap:20px;flex-wrap:wrap;justify-content:center;position:relative;z-index:2}\n.ps-cta-btn{position:static;overflow:visible;display:inline-flex;align-items:center;gap:8px;padding:16px 32px;border-radius:8px;line-height:1.6}\n@media(max-width:767px){\n  .ps-cta-title{font-size:28px;margin-bottom:16px}\n  .ps-cta-subtitle{font-size:16px;margin-bottom:32px}\n  .ps-cta-btn-row{flex-direction:column;align-items:stretch;gap:16px}\n  .ps-cta-btn{width:100%;max-width:300px;margin:0 auto;text-align:center}\n}\n@media(prefers-reduced-motion:reduce){.ps-cta-btn{transition:none !important}.ps-cta-btn::before{display:none}}\n\n/* === TB BODY WRAPPER RESET (must be last — beats :has() rules and Divi mobile padding) === */\n/* .et-l--body doesn\'t exist on all WP/Divi versions — use [class*="tb_body"] directly */\n.et_pb_section[class*="tb_body"].et_section_regular{background:transparent !important;background-image:none !important;padding:0 !important;margin:0 !important}\n.et_pb_row[class*="tb_body"].et_pb_row{max-width:100% !important;width:100% !important;padding:0 !important;margin:0 !important}\n.et_pb_column[class*="tb_body"]{padding:0 !important;margin:0 !important}\n@media(max-width:640px){\n  .et_pb_section .et_pb_row[class*="tb_body"].et_pb_row{padding:0 !important}\n}');

